# matter_retention.py — legal matter lifecycle
import boto3
from datetime import datetime, timedelta

def close_matter(matter_id: str, jurisdiction: str, matter_type: str):
    """Set final retention policy when a legal matter closes."""
    s3 = boto3.client("s3", region_name=get_region(jurisdiction))
    prefix = f"matters/{matter_id}/"

    # Determine retention period
    if matter_type == "litigation":
        retention_years = 10  # typical litigation hold
    elif jurisdiction == "EU":
        retention_years = 3   # GDPR-appropriate for non-privilege docs
    else:
        retention_years = 7   # state bar default

    expiry = datetime.utcnow() + timedelta(days=365 * retention_years)

    # Tag all objects in the matter prefix
    paginator = s3.get_paginator("list_objects_v2")
    for page in paginator.paginate(Bucket="legal-agent-storage", Prefix=prefix):
        for obj in page.get("Contents", []):
            s3.put_object_tagging(
                Bucket="legal-agent-storage",
                Key=obj["Key"],
                Tagging={"TagSet": [
                    {"Key": "matter_id", "Value": matter_id},
                    {"Key": "expires_at", "Value": expiry.isoformat()},
                    {"Key": "jurisdiction", "Value": jurisdiction}
                ]}
            )
    print(f"Matter {matter_id} retention set: expires {expiry.date()}")
